solution:
// O(n) time, O(n) space.
// We walk the array once. For each value, ask: 'has the Set seen it?'.
// If yes → return it. If no → add and continue.
function findDuplicate(nums) {
  const seen = new Set();
  for (const x of nums) {
    if (seen.has(x)) return x;  // first repeat encountered
    seen.add(x);
  }
  return -1;
}
